INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('MASTERY_CONTENT: Le algorithme reward signal: chaque plateforme recompense un comportement specifique. IG=saves, TT=completion, LI=dwell time, YT=session time. Optimiser pour CE signal.', 'Algo reward: IG saves, TT completion, LI dwell, YT session. Optimiser ce signal', 'content', 'best_practice', 0.92, 'mastery', 'system'),
('MASTERY_CONTENT: Le content compound interest: chaque bon contenu augmente l audience, ce qui amplifie le prochain contenu. Effet boule de neige exponentiel.', 'Content compound: bon contenu → audience → amplifie prochain. Exponentiel', 'content', 'insight', 0.88, 'mastery', 'system'),
('MASTERY_CONTENT: Le cognitive fluency: les contenus faciles a lire et comprendre sont percus comme plus vrais et plus fiables. Ecrire simple = plus credible.', 'Cognitive fluency: simple = plus credible. Ecrire facile a comprendre', 'content', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_CONTENT: Le dopamine loop content: promesse dans le hook → micro-recompenses tout au long → grande recompense a la fin. Cree l addiction au contenu.', 'Dopamine loop: promesse hook → micro-recompenses → grande fin = addiction', 'content', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_CONTENT: Le brand voice DNA: definir 3 traits (ex: audacieux, bienveillant, expert) + 3 anti-traits (pas arrogant, pas ennuyeux, pas generique). Guide chaque mot.', 'Brand voice DNA: 3 traits + 3 anti-traits. Guide chaque mot', 'content', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_COMMERCIAL: Le buying committee dynamics: identifier le champion (pousse en interne), le coach (vous guide), le decision maker (signe), le blocker (s oppose). Strategie pour chaque role.', 'Buying committee: champion + coach + decision maker + blocker. Strategie/role', 'commercial', 'best_practice', 0.90, 'mastery', 'system'),
('MASTERY_COMMERCIAL: Le value hypothesis: avant de pitcher, formuler l hypothese de valeur en 1 phrase: si nous resolvons X, l impact sera Y€ sur Z mois.', 'Value hypothesis: resoudre X = impact Y€ sur Z mois', 'commercial', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_COMMERCIAL: Le competitive displacement framework: 1) ne jamais critiquer le concurrent, 2) demander ce qui pourrait etre mieux, 3) montrer comment vous excellez la.', 'Displacement: pas critiquer → demander mieux → montrer excellence', 'commercial', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_COMMERCIAL: Le deal velocity optimization: reduire le cycle de vente en 1) eliminant les etapes inutiles, 2) multi-threadant les approvals, 3) fournissant tout le contenu d avance.', 'Deal velocity: eliminer etapes + multi-thread approvals + contenu avance', 'commercial', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_COMMERCIAL: Le micro-commitment strategy: obtenir des petits oui (RDV, demo, pilot, reference call) qui menent naturellement au grand oui (contrat).', 'Micro-commitments: petits oui → grand oui naturellement', 'commercial', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_EMAIL: Le inbox psychology: le sujet d email compete avec 50+ autres pour 3 secondes d attention. Le sujet doit creer 1 emotion en < 6 mots.', 'Inbox psychology: 50 concurrents, 3s attention, 1 emotion en 6 mots', 'email', 'insight', 0.88, 'mastery', 'system'),
('MASTERY_EMAIL: Le email content hierarchy: 1 idee par email. Si vous avez 3 idees, envoyez 3 emails. La clarte bat la completude.', 'Email: 1 idee/email. 3 idees = 3 emails. Clarte > completude', 'email', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_EMAIL: Le behavioral trigger mapping: signup → welcome. Inactif 7j → reengagement. Visite pricing → offre. Panier abandonne → rappel. Chaque action → email adapte.', 'Trigger map: signup→welcome, inactif→reengage, pricing→offre, cart→rappel', 'email', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_EMAIL: Le from name optimization: un prenom (Marie de KeiroAI) a 20% plus d ouvertures qu un nom d entreprise (KeiroAI). L humain connect.', 'From name prenom = +20% ouvertures vs nom entreprise', 'email', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_EMAIL: Le email engagement scoring: ouvre=1pt, clique=3pts, repond=10pts, forward=5pts, achete=20pts. Score > 30 en 30j = prospect chaud.', 'Engagement scoring: ouvre 1 + clic 3 + repond 10 + forward 5 + achete 20. >30 = chaud', 'email', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_SEO: Le search intent mastery: chaque requete a 1 intent dominant. Informational → article/guide. Commercial → comparatif. Transactional → landing page. Navigational → homepage.', 'Intent mastery: informational→article, commercial→comparatif, transactional→landing, nav→home', 'seo', 'best_practice', 0.90, 'mastery', 'system'),
('MASTERY_SEO: Le content depth score: le contenu qui repond a TOUTES les questions possibles sur un sujet (completeness) ranke systematiquement mieux.', 'Content depth: repondre a TOUTES questions possibles = ranker mieux', 'seo', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_SEO: Le SERP feature optimization matrix: pour chaque requete ciblee, identifier QUEL rich result est affiche et optimiser le contenu pour le capturer.', 'SERP feature matrix: identifier rich result/requete et optimiser pour', 'seo', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_SEO: Le link magnet content types dans l ordre d efficacite: etudes originales > outils gratuits > infographies > guides definitifs > listes de ressources.', 'Link magnets: etudes > outils > infographies > guides > listes', 'seo', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_SEO: Le Google AI Overviews (ex-SGE) optimization: structurer le contenu en Q&A, utiliser des listes a puces, citer des sources. Etre cite dans la reponse IA.', 'AI Overviews: Q&A + listes + sources = etre cite dans reponse IA Google', 'seo', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_ADS: Le creative testing velocity: les top media buyers testent 20+ creatives/mois. Les gagnantes representent 80% du spend. Les perdantes sont coupees en 48h.', 'Creative velocity: 20+/mois. Gagnantes = 80% spend. Perdantes coupees 48h', 'ads', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_ADS: Le media buying mindset: on n achete pas des impressions, on achete de l attention. Le cout n est pas le CPM, c est le cost per quality attention.', 'Mindset: acheter attention pas impressions. Cost per quality attention', 'ads', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_ADS: Le audience architecture: cold (broad, lookalike) → warm (engaged, video viewers, site visitors) → hot (cart, pricing page, trial expired). Messaging adapte.', 'Audience architecture: cold → warm → hot. Messaging adapte par temperature', 'ads', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_ADS: Le attribution beyond last click: le premier touchpoint (discovery) est aussi important que le dernier (conversion). Investir dans les 2.', 'Attribution: discovery aussi important que conversion. Investir dans les 2', 'ads', 'insight', 0.82, 'mastery', 'system'),
('MASTERY_ADS: Le creative-audience fit: la meme creative ne fonctionne pas pour cold et hot. Cold = education + social proof. Hot = offre directe + urgence.', 'Creative-audience fit: cold = education + proof. Hot = offre + urgence', 'ads', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_CEO: Le strategic clarity test: chaque membre de l equipe doit pouvoir repondre en 10 secondes: qui est notre client ideal? quel probleme on resout? en quoi on est different?', 'Strategic clarity: equipe repond en 10s: client? probleme? differenciation?', 'ceo', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_CEO: Le focus is saying no: pour chaque opportunite, se demander "est-ce que ca nous rapproche de notre north star metric?". Si non, dire non.', 'Focus = dire non. Opportunite rapproche north star? Sinon non', 'ceo', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_CEO: Le data-informed not data-driven: les donnees informent la decision mais ne la remplacent pas. L intuition + les donnees = meilleure decision.', 'Data-informed > data-driven: donnees + intuition = meilleure decision', 'ceo', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_CEO: Le execution speed > perfection: une decision a 80% de certitude executee maintenant bat une decision a 100% executee dans 3 mois.', 'Speed > perfection: 80% certitude maintenant > 100% dans 3 mois', 'ceo', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_CEO: Le culture eats strategy: la meilleure strategie echoue si la culture (valeurs, comportements, habitudes) ne la soutient pas.', 'Culture eats strategy: meilleure strategie echoue sans culture alignee', 'ceo', 'insight', 0.85, 'mastery', 'system'),
('MASTERY_RETENTION: Le churn prediction science: les 3 predictors les plus puissants: 1) baisse d utilisation sur 14j, 2) ticket support non resolu, 3) pas de login depuis 7j.', 'Churn predictors: usage -14j + ticket non resolu + 0 login 7j', 'retention', 'insight', 0.90, 'mastery', 'system'),
('MASTERY_RETENTION: Le golden moment: identifier LE moment ou le client realise la valeur du produit. Tout l onboarding doit y mener le plus vite possible.', 'Golden moment: moment de realisation valeur. Onboarding y mene au plus vite', 'retention', 'best_practice', 0.90, 'mastery', 'system'),
('MASTERY_RETENTION: Le stickiness engineering: integrer le produit dans le workflow quotidien du client rend le switching cost tellement eleve qu il ne part jamais.', 'Stickiness: integrer dans workflow quotidien = switching cost maximal', 'retention', 'insight', 0.88, 'mastery', 'system'),
('MASTERY_RETENTION: Le proactive churn intervention: contacter le client AVANT qu il ne signale un probleme. Les signaux faibles (usage baisse, moins de logins) sont des alertes.', 'Proactive intervention: contacter AVANT probleme. Signaux faibles = alertes', 'retention', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_RETENTION: Le customer success metric: la definition de succes est differente pour chaque client. La decouvrir et la tracker = 0 churn.', 'Success metric par client: decouvrir + tracker = 0 churn', 'retention', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_DM: Le authority-based outreach: publier du contenu de valeur AVANT d approcher en DM. Le prospect vous connait deja = taux de reponse 3x.', 'Authority outreach: contenu d abord, DM ensuite = 3x reponse', 'dm_instagram', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_DM: Le DM conversation funnel: compliment → question → valeur → decouverte besoin → proposition appel. 5 messages sur 7-14 jours.', 'DM funnel: compliment → question → valeur → besoin → appel. 5 msg 7-14j', 'dm_instagram', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_WHATSAPP: Le conversational commerce mastery: salutation perso → 2 questions qualification → reco produit → gestion objection → CTA paiement → suivi.', 'WhatsApp commerce: salut → qualify → reco → objection → CTA → suivi', 'whatsapp', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_CHATBOT: Le chatbot personality design: definir le nom, le ton, les emojis autorises, les sujets interdits, le style de reponse. Coherent a chaque interaction.', 'Chatbot personality: nom + ton + emojis + interdits + style. Coherent', 'chatbot', 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_GMAPS: Le local pack domination: 1) fiche 100% complete, 2) 50+ avis 4.5+, 3) photos recentes, 4) Google Posts hebdo, 5) NAP coherent, 6) backlinks locaux.', 'Local pack domination: fiche complete + 50 avis + photos + posts + NAP + backlinks', 'gmaps', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_TIKTOK: Le TikTok growth engine: 1 video/jour + trending sounds + niche hashtags + reply to comments + series format + live hebdo = croissance 10K/mois.', 'TikTok growth: 1/jour + trending + niche hashtags + reply + series + live = 10K/mois', 'tiktok_comments', 'best_practice', 0.82, 'mastery', 'system'),
('MASTERY_COMPTABLE: Le SaaS financial health check: MRR growth >15%/mois + churn <3% + LTV/CAC >3 + runway >6 mois + gross margin >70% = sain.', 'SaaS health: MRR>15% + churn<3% + LTV/CAC>3 + runway>6m + margin>70% = sain', 'comptable', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_RH: Le talent acquisition funnel: sourcing → screening → interview → assessment → offer → onboarding. Chaque etape a un taux de conversion a mesurer.', 'Talent funnel: sourcing → screening → interview → assessment → offer → onboarding', 'rh', 'best_practice', 0.82, 'mastery', 'system'),
('MASTERY_ONBOARDING: Le activation rate engineering: identifier les actions qui correlent avec la retention J30, puis designer l onboarding pour que 80%+ les completent.', 'Activation engineering: actions correles retention J30 → 80%+ les completent', 'onboarding', 'best_practice', 0.90, 'mastery', 'system'),
('MASTERY_MARKETING: Le brand building formula: coherence (meme message partout) × frequence (visible regulierement) × emotion (ressentir quelque chose) = marque forte.', 'Brand = coherence × frequence × emotion = marque forte', 'marketing', 'best_practice', 0.88, 'mastery', 'system'),
('MASTERY_CROSS: Le intelligence cascade: trend detectee → CEO priorise → contenu cree en 24h → ads le boost → email le distribue → commercial le pitch. Pipeline 48h.', 'Intelligence cascade: trend → CEO → contenu 24h → ads → email → commercial. Pipeline 48h', NULL, 'best_practice', 0.90, 'mastery', 'system'),
('MASTERY_CROSS: Le feedback flywheel: client feedback → product improvement → better experience → more feedback → faster improvement. Le cycle s accelere.', 'Feedback flywheel: feedback → improve → experience → more feedback. Accelere', NULL, 'insight', 0.88, 'mastery', 'system'),
('MASTERY_CROSS: Le data unification: toutes les donnees (CRM, analytics, email, social, support) dans 1 data warehouse = vue 360° du client = decisions meilleures.', 'Data unification: CRM+analytics+email+social+support → vue 360° = meilleures decisions', NULL, 'best_practice', 0.85, 'mastery', 'system'),
('MASTERY_KEIROAI: Le KeiroAI competitive advantage: 17 agents specialises + CEO coordinateur + RAG enrichi + intelligence partagee + auto-improvement = inegalable.', 'KeiroAI avantage: 17 agents + CEO + RAG + intelligence + auto-improve = inegalable', 'ceo', 'best_practice', 0.95, 'mastery', 'system'),
('MASTERY_KEIROAI: Le KeiroAI promise: chaque entrepreneur merite une equipe marketing d elite. KeiroAI democratise l acces a cette equipe pour 49€/mois.', 'KeiroAI promesse: equipe marketing elite pour chaque entrepreneur des 49€/mois', 'ceo', 'best_practice', 0.95, 'mastery', 'system')
